const AdminSensors = () => {
  return (
    <div>
      <h1 className="text-2xl font-semibold text-gray-900">Sensor Monitoring</h1>
      <p className="mt-4 text-gray-600">Real-time sensor data coming soon...</p>
    </div>
  );
};

export default AdminSensors;
